import torch
import matplotlib.pyplot as plt
import numpy as np
import random

#Functions to model the equations

#Z-traces

def update_Z_i(Z_i_prev, S_i_prev, k_z):
    return (1-k_z) * Z_i_prev + k_z * S_i_prev


def update_Z_j(Z_j_prev, S_j_prev, k_z):
    return (1-k_z) * Z_j_prev + k_z * S_j_prev

#P-traces
def update_P_i(P_i_prev, Z_i_prev, k_p):
    return (1-k_p)*P_i_prev + k_p*Z_i_prev

def update_P_j(P_j_prev, Z_j_prev, k_p):
    return (1-k_p)*P_j_prev + k_p*Z_j_prev

def update_P_ij(P_ij_prev, Z_i_prev, Z_j_prev, k_p):
    return (1-k_p)*P_ij_prev + k_p * Z_i_prev*Z_j_prev

#weight updates
def update_beta_j(P_j_prev, epsilon):
    return torch.log(P_j + epsilon)

def update_W_ij(P_ij_prev, P_i_prev, P_j_prev, epsilon):
    return torch.log(P_ij_prev + epsilon**2) - torch.log(P_i_prev + epsilon) - torch.log(P_j_prev  + epsilon)

#Parameters required
num_steps = 1000
k_z = round(float(1/11),4) #k_zi = k_zj = 1/11
k_p = round(float(1/500),4) #k_p = 1/500
epsilon = 0.01

#Firing rate for spikes
burst_prob = 0.5

S_i = torch.zeros(1, dtype=torch.float64)
S_j = torch.zeros(1, dtype=torch.float64)

Z_i = torch.zeros(1,dtype=torch.float64)
Z_j = torch.zeros(1,dtype=torch.float64)

P_i = torch.zeros(1,dtype=torch.float64)
P_j = torch.zeros(1,dtype=torch.float64)


W_ij = torch.zeros(1,dtype=torch.float64)
P_ij = torch.zeros(1,dtype=torch.float64)


S_i_list =[]
S_j_list=[]
Z_i_list =[]
Z_j_list =[]
P_i_list =[]
P_j_list =[]
P_ij_list =[]
W_ij_list =[]


#Execution and plotting
for step in range(num_steps):
  W_ij = update_W_ij(P_ij, P_i, P_j, epsilon) #weight update W_ij = log((Pij + epsilon^2)/(Pi + epsilon)(Pj + epsilon))
  W_ij_list.append(W_ij)

#Probability traces
  P_ij = update_P_ij(P_ij, Z_i, Z_j, k_p) #Pij(t) = Pij(t-1)*(1-kp) + Zi(t-1)*Zj(t-1)*kp
  P_ij_list.append(P_ij)
  P_i = update_P_i(P_i, Z_i, k_p) #Pi(t) = Pi(t-1)*(1-kp) + Zi(t-1)*kp
  P_i_list.append(P_i)
  P_j = update_P_j(P_j, Z_j, k_p) #Pj(t) = Pj(t-1)*(1-kp) + Zj(t-1)*kp
  P_j_list.append(P_j)

#Z-traces
  Z_i = update_Z_i(Z_i, S_i, k_z)
  Z_i_list.append(Z_i)
  Z_j = update_Z_j(Z_j, S_j, k_z)
  Z_j_list.append(Z_j)



  if(90<=step<=150 or 500 <=step <=600):
    if(random.random() > burst_prob):
      S_i = 1.0
      S_i_list.append(S_i)
    else:
      S_i = 0.0
      S_i_list.append(S_i)
  else:
    S_i = 0.0
    S_i_list.append(S_i)

  if(220<=step<=260 or 530<=step<=700):
    if(random.random() > burst_prob):
      S_j = 1.0
      S_j_list.append(S_j)
    else:
      S_j = 0.0
      S_j_list.append(S_j)
  else:
    S_j = 0.0
    S_j_list.append(S_j)



fig,ax = plt.subplots(4,1,figsize=(10,5))

time_axis = np.arange(num_steps) * 0.001

ax[0].plot(time_axis, S_i_list, color = 'steelblue', linewidth = 1)
ax[0].plot(time_axis,S_j_list, color = 'forestgreen', linewidth = 1)
ax[0].set_xlabel("Time (s)")
ax[0].set_ylabel("Spikes")
ax[0].set_ylim(-0.1, 1.0) # Binary range
ax[0].legend(["i","j","ij"], loc="right")


ax[1].plot(time_axis,Z_i_list,  color = 'steelblue', linewidth = 1)
ax[1].plot(time_axis,Z_j_list,  color = 'forestgreen', linewidth = 1)
ax[1].set_xlabel("Time (s)")
ax[1].set_ylabel("Z-traces")
ax[1].set_ylim(-0.1, 0.9) # Binary range
ax[1].legend(["i","j","ij"], loc="right")


ax[2].plot(time_axis,P_i_list,  color = 'steelblue', linewidth = 1)
ax[2].plot(time_axis,P_j_list,  color = 'forestgreen', linewidth = 1)
ax[2].plot(time_axis,P_ij_list, color= 'orange', linewidth = 1)
ax[2].set_xlabel("Time (s)")
ax[2].set_ylabel("P-traces")
ax[2].set_ylim(0, 0.15) # Binary range
ax[2].legend(["i","j","ij"],loc="right")

ax[3].plot(time_axis, W_ij_list, color = 'orange', linewidth =1)
ax[3].set_xlabel("Time (s)")
ax[3].set_ylabel("Weights")
ax[3].set_ylim(-3, 3) # Binary range
ax[3].legend(["ij"],loc="right")

ax[0].set_title("Simplified BCPNN learning rule ")


plt.tight_layout(pad=0.00001)
plt.show()

